/*
 * 模块分类 · Loon 资源解析器
 * 细项描述 · 智能节点重命名 / 旗帜补全 / 台湾旗帜模式
 *
 * 参数说明
 * · prefix=前缀文本
 * · twflag=1    台湾显示 🇹🇼
 * · twflag=0    关闭台湾特殊旗帜处理
 * · twflag=-1   台湾显示 🇼🇸
 *
 * 使用示例
 * · prefix=[机场]&twflag=1
 * · prefix=IEPL-&twflag=0
 * · twflag=-1
 */

var type = typeof $resourceType !== "undefined" ? $resourceType : 0;
var resource = typeof $resource !== "undefined" ? String($resource || "") : "";
var result = "";

function parseArgument() {
  var raw = "";
  var obj = {};
  var parts, i, item, idx, key, value;

  if (typeof $argument !== "undefined" && $argument) raw = String($argument);
  else if (typeof $args !== "undefined" && $args) raw = String($args);
  else if (typeof $parameter !== "undefined" && $parameter) raw = String($parameter);

  if (!raw) return obj;

  parts = raw.split("&");
  for (i = 0; i < parts.length; i++) {
    item = parts[i];
    if (!item) continue;

    idx = item.indexOf("=");
    if (idx === -1) {
      obj[String(item).trim()] = "";
      continue;
    }

    key = item.slice(0, idx).trim();
    value = item.slice(idx + 1).trim();

    try {
      value = decodeURIComponent(value);
    } catch (e) {}

    obj[key] = value;
  }

  return obj;
}

var ARG = parseArgument();
var PREFIX = typeof ARG.prefix === "string" ? ARG.prefix : "";
var TWFLAG = String(typeof ARG.twflag !== "undefined" ? ARG.twflag : "1");

